{"output":"/**
 * Arc Diagram Builder for G2 v5
 *
 * Uses G2's line + point marks with custom data transforms
 * to create arc diagrams with linear or circular layouts
 */

import { ChartBuilder, type ChartSpec } from '../base';

export class ArcDiagramBuilder extends ChartBuilder {
  buildScriptTags(): string {
    return '<script src="https://cdn.jsdelivr.net/npm/@antv/g2@5/dist/g2.min.js"></script>';
  }

  buildHtml(spec: ChartSpec): string {
    const data = spec.data ?? { nodes: [], edges: [] };
    const layout = spec.layout || 'linear';
    const width = spec.width || 600;
    const height = spec.height || 400;
    const theme = spec.theme || 'light';

    const chartScript = `
  const { Chart } = G2;

  const chart = new Chart({
    container: 'container',
    width: ${width},
    height: ${height},
    theme: 'classic',
  });

  const rawData = ${JSON.stringify(data)};
  const layout = '${layout}';

  chart.options({
    type: 'view',
    data: {
      value: rawData,
      transform: [{
        type: 'custom',
        callback: (data) => {
          const { nodes, edges } = data;

    if (layout === 'circular') {
      // Circular layout
      const centerX = ${width} / 2;
      const centerY = ${height} / 2;
      const radius = Math.min(${width}, ${height}) / 2 - 80;
      const nodeCount = nodes.length;

      // Position nodes in circle
      const nodePositions = nodes.map((node, i) => {
        const angle = (i / nodeCount) * 2 * Math.PI - Math.PI / 2;
        const x = centerX + radius * Math.cos(angle);
        const y = centerY + radius * Math.sin(angle);
        return {
          ...node,
          x: x,
          y: y,
          type: 'node'
        };
      });

      // Create arc data using quadratic bezier curves through center
      const arcData = [];
      edges.forEach(edge => {
        const sourceNode = nodePositions.find(n => n.id === edge.source);
        const targetNode = nodePositions.find(n => n.id === edge.target);

        if (sourceNode && targetNode) {
          const steps = 20;
          for (let i = 0; i <= steps; i++) {
            const t = i / steps;
            // Quadratic bezier with center as control point
            const x = Math.pow(1 - t, 2) * sourceNode.x +
                     2 * (1 - t) * t * centerX +
                     Math.pow(t, 2) * targetNode.x;
            const y = Math.pow(1 - t, 2) * sourceNode.y +
                     2 * (1 - t) * t * centerY +
                     Math.pow(t, 2) * targetNode.y;

            arcData.push({
              x: x,
              y: y,
              linkId: \`\${edge.source}-\${edge.target}\`,
              type: 'link'
            });
          }
        }
      });

      return [...arcData, ...nodePositions];
    } else {
      // Linear layout
      const nodeData = [];
      const arcData = [];
      const W = ${width};
      const H = ${height};
      const pad = 50;
      const nodeY = H - 100;

      // Position nodes linearly
      nodes.forEach((node, i) => {
        const x = nodes.length > 1
          ? pad + (i / (nodes.length - 1)) * (W - 2 * pad)
          : W / 2;
        nodeData.push({
          ...node,
          x: x,
          y: nodeY,
          type: 'node'
        });
      });

      // Create arcs as parabolic curves
      edges.forEach(edge => {
        const sourceNode = nodeData.find(n => n.id === edge.source);
        const targetNode = nodeData.find(n => n.id === edge.target);

        if (sourceNode && targetNode) {
          const distance = Math.abs(targetNode.x - sourceNode.x);
          const arcHeight = Math.min(150, distance * 0.3);
          const steps = 15;

          for (let i = 0; i <= steps; i++) {
            const t = i / steps;
            const x = sourceNode.x + (targetNode.x - sourceNode.x) * t;
            const y = nodeY - arcHeight * Math.sin(Math.PI * t);

            arcData.push({
              x: x,
              y: y,
              linkId: \`\${edge.source}-\${edge.target}\`,
              type: 'link'
            });
          }
        }
      });

          return [...arcData, ...nodeData];
        }
      }]
    }
  });

  // Draw arcs/edges
  chart
    .line()
    .data({ transform: [{ type: 'filter', callback: (d) => d.type === 'link' }] })
    .encode('x', 'x')
    .encode('y', 'y')
    .encode('series', 'linkId')
    .style('stroke', '#A3B1BF')
    .style('strokeWidth', 1.5)
    .style('strokeOpacity', 0.4)
    .style('lineCap', 'round');

  // Draw nodes
  chart
    .point()
    .data({ transform: [{ type: 'filter', callback: (d) => d.type === 'node' }] })
    .encode('x', 'x')
    .encode('y', 'y')
    .style('r', 6)
    .style('fill', '#5B8FF9')
    .style('stroke', '#fff')
    .style('strokeWidth', 2)
    .style('fillOpacity', 0.9);

  // Draw node labels
  chart
    .text()
    .data({ transform: [{ type: 'filter', callback: (d) => d.type === 'node' }] })
    .encode('x', 'x')
    .encode('y', 'y')
    .encode('text', (d) => d.label || d.id)
    .style('textAlign', 'center')
    .style('textBaseline', 'middle')
    .style('fontSize', 11)
    .style('fill', '#333')
    .style('fontWeight', 'normal')
    .style('dy', layout === 'circular' ? -15 : 15);

  chart.render();
`;

    return this.buildContainer(spec, chartScript);
  }
}
