+    .data({ transform: [{ type: 'filter', callback: (d) => d.type === 'node' }] })
+    .encode('x', 'x')
+    .encode('y', 'y')
+    .encode('text', (d) => d.label || d.id)
+    .style('textAlign', 'center')
+    .style('textBaseline', 'middle')
+    .style('fontSize', 11)
+    .style('fill', '#333')
+    .style('fontWeight', 'normal')
+    .style('dy', '${layout}' === 'circular' ? -15 : 15);
+
+  chart.render();
