  serverUrl?: string;
};

export function createChartUIResource({
  uri,
  html,
  title,
  description,
  mode,
  serverUrl,
}: CreateChartUIResourceOptions): UIResource {
  if (mode === "server" && serverUrl) {
    return {
      type: "ui",
      name: title,
      uri,
      fallback: {
        type: "text",
        text: serverUrl,
      },
      spec: {
        title,
        description,
        htmlUrl: serverUrl,
      },
    };
  }

  return {
    type: "ui",
    name: title,
    uri,
    spec: {
      title,
      description,
      html,
    },
  };
}
