  for (const file of chartFiles) {
    const type = file.replace(/\.(basic|advanced)\.json$/, "");
    if (CHART_TYPE_MAP[type]) {
      examples.push({
        type: CHART_TYPE_MAP[type],
        file: resolve(chartsDir, file),
        name: file.replace(".json", ""),
        category: "charts",
